    predefined_subtasks_hint: { en: "These will be added automatically when the template is used.", ru: "Они будут автоматически добавлены при использовании шаблона.", da: "Disse tilføjes automatisk, når skabelonen bruges.", no: "Disse legges til automatisk når malen brukes.", sv: "Dessa läggs till automatiskt när mallen används.", de: "Diese werden automatisch hinzugefügt, wenn die Vorlage verwendet wird.", uk: "Вони будуть автоматично додані під час використання шаблону.", pl: "Zostaną dodane automatycznie po użyciu szablonu.", pirate: "These be added automatically when the pattern be used.", lolcat: "Dese get added automagically when templatey is used.", craft: "These will be added automatically when the blueprint is used." },
