    template_applied_priority: { en: "Priority: {value}", ru: "Приоритет: {value}", da: "Prioritet: {value}", no: "Prioritet: {value}", sv: "Prioritet: {value}", de: "Priorität: {value}", uk: "Пріоритет: {value}", pl: "Priorytet: {value}", pirate: "Priority: {value}", lolcat: "Prio: {value}", craft: "Tier: {value}" },
    template_applied_deadline: { en: "Deadline offset: {count}h", ru: "Смещение срока: {count} ч", da: "Deadlineforskydning: {count} t", no: "Fristforskyvning: {count} t", sv: "Deadlineförskjutning: {count} h", de: "Fristversatz: {count} Std", uk: "Зміщення дедлайну: {count} год", pl: "Przesunięcie terminu: {count} godz.", pirate: "Deadline offset: {count}h", lolcat: "Due offset: {count}h", craft: "Timer offset: {count}h" },
    template_created_task_note: { en: "Template subtasks will be added when you create the task.", ru: "Подзадачи шаблона будут добавлены при создании задачи.", da: "Skabelonens underopgaver bliver tilføjet, når du opretter opgaven.", no: "Malens deloppgaver legges til når du oppretter oppgaven.", sv: "Mallens deluppgifter läggs till när du skapar uppgiften.", de: "Die Unteraufgaben der Vorlage werden hinzugefügt, wenn du die Aufgabe erstellst.", uk: "Підзавдання шаблону будуть додані під час створення завдання.", pl: "Podzadania z szablonu zostaną dodane podczas tworzenia zadania.", pirate: "Pattern sub-duties will be added when ye create the duty.", lolcat: "Templatey subtaskies get added when yu make tasky.", craft: "Blueprint subtasks will be added when you create the quest." },
    update_templates_desc: { en: "Added reusable task templates with predefined subtasks and creator autofill.", ru: "Добавлены многоразовые шаблоны задач с предустановленными подзадачами и автозаполнением в конструкторе.", da: "Tilføjede genbrugelige opgaveskabeloner med foruddefinerede underopgaver og automatisk udfyldning i opretteren.", no: "La til gjenbrukbare oppgavemaler med forhåndsdefinerte deloppgaver og autofyll i oppretteren.", sv: "Lade till återanvändbara uppgiftsmallar med fördefinierade deluppgifter och autofyll i skaparen.", de: "Wiederverwendbare Aufgabenvorlagen mit vordefinierten Unteraufgaben und Autofill im Ersteller wurden hinzugefügt.", uk: "Додано багаторазові шаблони завдань із попередньо заданими підзавданнями та автозаповненням у створювачі.", pl: "Dodano wielorazowe szablony zadań z gotowymi podzadaniami i automatycznym uzupełnianiem w kreatorze.", pirate: "Added reusable duty patterns with pre-set sub-duties an' autofill in the creator.", lolcat: "Added reusable tasky templatez with pre-made subtaskies an autofill in creator.", craft: "Added reusable task templates with predefined subtasks and creator autofill." },
    update_templates_point_1: { en: "Users can now save personal templates with a name, optional description, reusable subtasks, and optional defaults.", ru: "Теперь пользователи могут сохранять личные шаблоны с названием, необязательным описанием, многоразовыми подзадачами и необязательными значениями по умолчанию.", da: "Brugere kan nu gemme personlige skabeloner med navn, valgfri beskrivelse, genbrugelige underopgaver og valgfri standarder.", no: "Brukere kan nå lagre personlige maler med navn, valgfri beskrivelse, gjenbrukbare deloppgaver og valgfrie standardverdier.", sv: "Användare kan nu spara personliga mallar med namn, valfri beskrivning, återanvändbara deluppgifter och valfria standardvärden.", de: "Benutzer können jetzt persönliche Vorlagen mit Name, optionaler Beschreibung, wiederverwendbaren Unteraufgaben und optionalen Standardwerten speichern.", uk: "Користувачі тепер можуть зберігати особисті шаблони з назвою, необов’язковим описом, багаторазовими підзавданнями та необов’язковими типовими значеннями.", pl: "Użytkownicy mogą teraz zapisywać własne szablony z nazwą, opcjonalnym opisem, wielorazowymi podzadaniami i opcjonalnymi ustawieniami domyślnymi.", pirate: "Users can now save personal patterns with a name, optional notes, reusable sub-duties, an' optional defaults.", lolcat: "Users can now save personal templatez with name, maybe-desc, reusable subtaskies, an optional defaultz.", craft: "Users can now save personal templates with a name, optional description, reusable subtasks, and optional defaults." },
    update_templates_point_2: { en: "The task creator now lets you start from scratch or choose a template that preloads subtasks and defaults.", ru: "Конструктор задач теперь позволяет начать с нуля или выбрать шаблон, который заранее загружает подзадачи и значения по умолчанию.", da: "Opretteren lader dig nu starte fra bunden eller vælge en skabelon, der forudindlæser underopgaver og standarder.", no: "Oppretteren lar deg nå starte fra bunnen eller velge en mal som forhåndslaster deloppgaver og standarder.", sv: "Skaparen låter dig nu börja från grunden eller välja en mall som förladdar deluppgifter och standardvärden.", de: "Der Aufgabenersteller lässt dich jetzt von Grund auf starten oder eine Vorlage wählen, die Unteraufgaben und Standardwerte vorlädt.", uk: "Створювач завдань тепер дозволяє почати з нуля або вибрати шаблон, який попередньо завантажує підзавдання та типові значення.", pl: "Kreator zadań pozwala teraz zacząć od zera albo wybrać szablon, który wstępnie ładuje podzadania i ustawienia domyślne.", pirate: "The duty creator now lets ye start fresh or choose a pattern that preloads sub-duties an' defaults.", lolcat: "Tasky creator now lets yu start frum scratch or pick templatey that preloads subtaskies an defaultz.", craft: "The task creator now lets you start from scratch or choose a template that preloads subtasks and defaults." },
    update_templates_point_3: { en: "Templates stay separate from real tasks, so they can be reused without cluttering the live workspace.", ru: "Шаблоны остаются отдельными от реальных задач, поэтому их можно переиспользовать, не загромождая рабочее пространство.", da: "Skabeloner holdes adskilt fra rigtige opgaver, så de kan genbruges uden at rode i arbejdsområdet.", no: "Maler holdes adskilt fra ekte oppgaver, slik at de kan gjenbrukes uten å rote til arbeidsområdet.", sv: "Mallar hålls separata från riktiga uppgifter så att de kan återanvändas utan att röra till arbetsytan.", de: "Vorlagen bleiben von echten Aufgaben getrennt, sodass sie wiederverwendet werden können, ohne den aktiven Arbeitsbereich zu überladen.", uk: "Шаблони залишаються окремими від реальних завдань, тому їх можна повторно використовувати без захаращення робочого простору.", pl: "Szablony pozostają oddzielone od prawdziwych zadań, więc można ich używać ponownie bez zaśmiecania aktywnej przestrzeni pracy.", pirate: "Patterns stay separate from real duties, so they can be reused without clutterin' the live deck.", lolcat: "Templatez stay separate from real taskies so yu can reuse dem without cluttering workspace.", craft: "Templates stay separate from real tasks, so they can be reused without cluttering the live workspace." },
