    chart_type: { en: "Chart type", ru: "Тип графика", da: "Diagramtype", no: "Diagramtype", sv: "Diagramtyp", de: "Diagrammtyp", uk: "Тип графіка", pirate: "Chart type", lolcat: "Chart typez", craft: "Chart type" },
