    completed_search_hint: { en: "Filter by someone who worked on the task or confirmed it complete.", ru: "Фильтруйте по тому, кто работал над задачей или подтвердил ее завершение.", da: "Filtrer efter en person, der arbejdede pa opgaven eller bekraeftede den som fuldfort.", no: "Filtrer etter noen som jobbet pa oppgaven eller bekreftet den som fullfort.", sv: "Filtrera efter nagon som arbetade med uppgiften eller bekraftade den som slutford.", de: "Filtere nach Personen, die an der Aufgabe gearbeitet oder den Abschluss bestatigt haben.", uk: "Фільтруйте за тими, хто працював над завданням або підтвердив його завершення.", pirate: "Filter by who worked the duty or confirmed it done.", lolcat: "Filter by who worked on tasky or confirmed it done.", craft: "Filter by someone who worked on the quest or confirmed it complete." },
    completed_search_user_label: { en: "User", ru: "Пользователь", da: "Bruger", no: "Bruker", sv: "Anvandare", de: "Benutzer", uk: "Користувач", pirate: "Crew mate", lolcat: "Hooman", craft: "Player" },
