    confirmed_by: { en: "Confirmed by", ru: "Подтвердил", da: "Bekraeftet af", no: "Bekreftet av", sv: "Bekraftad av", de: "Bestatigt von", uk: "Підтвердив", pirate: "Confirmed by", lolcat: "Confirmed by", craft: "Confirmed by" },
