    no_completed_tasks: { en: "No completed tasks yet.", ru: "Пока нет завершенных задач.", da: "Ingen fuldforte opgaver endnu.", no: "Ingen fullforte oppgaver enna.", sv: "Inga slutforda uppgifter annu.", de: "Noch keine abgeschlossenen Aufgaben.", uk: "Ще немає завершених завдань.", pirate: "No finished duties yet.", lolcat: "No done taskies yet.", craft: "No completed quests yet." },
    no_completed_tasks_for_user: { en: "No completed tasks matched that user.", ru: "Нет завершенных задач для этого пользователя.", da: "Ingen fuldforte opgaver matchede den bruger.", no: "Ingen fullforte oppgaver matchet den brukeren.", sv: "Inga slutforda uppgifter matchade den anvandaren.", de: "Keine abgeschlossenen Aufgaben passen zu diesem Benutzer.", uk: "Не знайдено завершених завдань для цього користувача.", pirate: "No finished duties matched that crew mate.", lolcat: "No done taskies matched dat hooman.", craft: "No completed quests matched that player." },
